import React , { useState,useEffect }  from "react";
import logo from "./images/logo.jpeg";
import Container from 'react-bootstrap/Container';
import Nav from 'react-bootstrap/Nav';
import Navbar from 'react-bootstrap/Navbar';
import "./App.css";
import Button from 'react-bootstrap/Button';
import Form from 'react-bootstrap/Form';
import { useNavigate ,Link } from 'react-router-dom';



function Login(){
  const navigate = useNavigate();

    const [data,setData] = useState({
        email :"",
        password :""
    })
    const handleInputChange = (event) => {
        const { name, value } = event.target;
        setData((prevFormData) => ({
          ...prevFormData,
          [name]: value,
        }));
      };

    function handleSubmit(event){
        event.preventDefault();



        if(data.email === ""  || data.password ===""){
            alert("enter email and password");
        }
        else{
          try{

            console.log(data.email);
            const sendDataToServer = async () => {
                
              

                const response = await fetch('/api/login', {
                  method: 'POST',
                  headers: {
                    'Content-Type': 'application/json',
                    
                  
                  },
                  body: JSON.stringify(data)
                });
            
                // Handle the response from the server if needed
                const result = await response.json();
                console.log("Result :" ,result);
                if(!response.ok){
                    alert(result.message);
                }
                else if(response.ok){
                  const token = result.data;
                  localStorage.setItem('token', token);
                  console.log("tokens" , localStorage.getItem('token'));
                  console.log("Retrieved token:", localStorage.getItem('token'));                  
                  navigate("/dashboard");
                }

        }
        sendDataToServer(); 

          }
          catch (error) {
            console.error('Error during login:', error);
            alert('An error occurred during login. Please try again.');
        }

    }
    }


    return(
        <div className="app">
        <Navbar bg="light" variant="light" expand="lg">
        <Container>
          <Navbar.Brand href="#home"><img
               src={logo}
              width="30"
              height="30"
              className="d-inline-block align-top"
              alt="React Bootstrap logo"
          /></Navbar.Brand>
          <Navbar.Toggle aria-controls="basic-navbar-nav" />
          <Navbar.Collapse id="basic-navbar-nav">
          <Nav className="me-auto">
          <Nav.Link as={Link} to="/contact">Contacts</Nav.Link>
          <Nav.Link as={Link} to="/">Home</Nav.Link>
          <Nav.Link as={Link} to="/register">Registration</Nav.Link>
          </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>

      <img className="socioLogo"
        src={logo}
        width="200"
        height="200"
      />

<Form onSubmit={handleSubmit}>
      <Form.Group className="mb-3" controlId="formBasicEmail">
        <Form.Label>Email address</Form.Label>
        <Form.Control type="email" name="email" value={data.email} onChange={handleInputChange} placeholder="Enter email" />
        <Form.Text className="text-muted">
          We'll never share your email with anyone else.
        </Form.Text>
      </Form.Group>

      <Form.Group className="mb-3" controlId="formBasicPassword">
        <Form.Label>Password</Form.Label>
        <Form.Control type="password" name="password" value={data.password} onChange={handleInputChange} placeholder="Password" />
      </Form.Group>
      <Form.Group className="mb-3" controlId="formBasicCheckbox">
      </Form.Group>
      <Button variant="danger" type="submit">
        Submit
      </Button>
    <nav>
    <ul>
    <li><Link to="/forgotpassword">Forgot Password</Link></li>
    
    </ul>
    </nav>
    </Form>
        </div>
    );
}

export default Login;
